import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Установка Java на Windows","description":"Пошаговая инструкция по установке Java на Windows.","frontmatter":{"title":"Установка Java на Windows","description":"Пошаговая инструкция по установке Java на Windows.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"ru_ru/1.20.4/players/installing-java/windows.md","filePath":"versions/1.20.4/translated/ru_ru/players/installing-java/windows.md","lastUpdated":1739538073000}`);var l={name:`ru_ru/1.20.4/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Установка Java на Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Установка Java на Windows”">​</a></h1><p>Этот гайд расскажет, как установить Java 17 на Windows.</p><p>Этот гайд понадобится вам, если вы хотите использовать установщик на основе <code>.jar</code> Fabric&#39;а, или если вы используете <code>.jar</code> сервера Minecraft.</p><h2 id="_1-проверьте-не-установлена-ли-java" tabindex="-1">1. Проверьте, не установлена ли Java <a class="header-anchor" href="#_1-проверьте-не-установлена-ли-java" aria-label="Permalink to “1. Проверьте, не установлена ли Java”">​</a></h2><p>Чтобы проверить, что Java уже установлена, вам нужно сначала открыть командную строку.</p><p>Вы можете сделать это, нажав <kbd>Win</kbd>+<kbd>R</kbd> и написав <code>cmd.exe</code> в появившемся окне.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Окно &quot;Выполнить&quot; с введённым &quot;cmd.exe&quot;" loading="lazy"></p><p>После того как вы открыли командную строку, впишите <code>java -version</code> и нажмите <kbd>Enter</kbd>.</p><p>Если команда выполнена успешно, вы увидите что-то вроде этого. Если выдало ошибку, то переходите к следующему шагу.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командная строка с введённой командой &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Чтобы использовать большинство современных версий Minecraft, вам потребуется установить как минимум Java 17. Если эта команда отображает любую версию ниже 17, вам придётся обновить Java.</p></div><h2 id="_2-скачивание-установщика-java-17" tabindex="-1">2. Скачивание установщика Java 17 <a class="header-anchor" href="#_2-скачивание-установщика-java-17" aria-label="Permalink to “2. Скачивание установщика Java 17”">​</a></h2><p>Чтобы установить Java 17, вам нужно скачать установщик с <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=17" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Вам нужно скачать версию <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium c выделенным Windows Installer (.msi)" loading="lazy"></p><p>Вам нужно выбрать <code>x86</code>, если у вас 32-битная система, или <code>x64</code>, если у вас 64-битная операционная система.</p><p>Большинство современных компьютеров имеют 64-битную операционную систему. Если вы не уверены, используйте 64-битный установщик.</p><h2 id="_3-запустите-установщик" tabindex="-1">3. Запустите установщик! <a class="header-anchor" href="#_3-запустите-установщик" aria-label="Permalink to “3. Запустите установщик!”">​</a></h2><p>Следуйте инструкциям в установщике, чтобы установить Java 17. Когда вы доходите до этой страницы, вы должны выбрать &quot;Entire feature will be installed on local hard drive&quot; для следующих функций:</p><ul><li><code>Set JAVA_HOME environment variable</code> - будет добавлено в PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Установщик Java 17 c выделенными &quot;Set JAVA_HOME variable&quot; и &quot;JavaSoft (Oracle) registry keys&quot;" loading="lazy"></p><p>После этого нажмите на <code>Next</code> и продолжите установку.</p><h2 id="_4-убедитесь-что-java-17-установлена" tabindex="-1">4. Убедитесь, что Java 17 установлена <a class="header-anchor" href="#_4-убедитесь-что-java-17-установлена" aria-label="Permalink to “4. Убедитесь, что Java 17 установлена”">​</a></h2><p>После того как установка закончится, вы можете проверить, что Java 17 установлена, открыв командную строку и вписав <code>java -version</code>.</p><p>Если команда будет выполнена успешно, вы увидите что-то вроде показанного ранее, где отображается версия Java:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командная строка с введённой командой &quot;java -version&quot;" loading="lazy"></p><p>Если вы столкнулись с какими-либо проблемами, попросите помощи в <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">дискорде Fabric</a> в канале <code>#player-support</code>.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};